void TriggerBinding::execute()
{
    bool curTrigState = condition();
    switch (type)
    {
        case Type::ON_TRUE:
        {
            if (curTrigState && !prevTrigState)
            {
                drivers->commandScheduler.addCommand(command);
            }
            break;
        }
        case Type::ON_FALSE:
        {
            if (!curTrigState && prevTrigState)
            {
                drivers->commandScheduler.addCommand(command);
            }
            break;
        }
        case Type::WHILE_TRUE:
        {
            if (curTrigState)
            {
                if (!drivers->commandScheduler.isCommandScheduled(command))
                {
                    drivers->commandScheduler.addCommand(command);
                }
            }
            else if (!curTrigState && prevTrigState)
            {
                drivers->commandScheduler.removeCommand(command, false);
            }
            break;
        }
        case Type::WHILE_FALSE:
        {
            if (!curTrigState)
            {
                if (!drivers->commandScheduler.isCommandScheduled(command))
                {
                    drivers->commandScheduler.addCommand(command);
                }
            }
            else if (curTrigState && !prevTrigState)
            {
                drivers->commandScheduler.removeCommand(command, false);
            }
            break;
        }
        case Type::TOGGLE_ON_TRUE:
        {
            if (curTrigState && !prevTrigState)
            {
                if (drivers->commandScheduler.isCommandScheduled(command))
                {
                    drivers->commandScheduler.removeCommand(command, false);
                }
                else
                {
                    drivers->commandScheduler.addCommand(command);
                }
            }
            break;
        }
        case Type::TOGGLE_ON_FALSE:
        {
            if (!curTrigState && prevTrigState)
            {
                if (drivers->commandScheduler.isCommandScheduled(command))
                {
                    drivers->commandScheduler.removeCommand(command, false);
                }
                else
                {
                    drivers->commandScheduler.addCommand(command);
                }
            }
            break;
        }
        case Type::ON_CHANGE:
        {
            if ((curTrigState && !prevTrigState) || (!curTrigState && prevTrigState))
            {
                drivers->commandScheduler.addCommand(command);
            }
            break;
        }
        case Type::DEBOUNCE:
        {
            if (!prevTrigState && curTrigState)
            {
                curTime = tap::arch::clock::getTimeMilliseconds();
            }
            if (curTrigState && tap::arch::clock::getTimeMilliseconds() - curTime > debounceTimeout)
            {
                if (!drivers->commandScheduler.isCommandScheduled(command))
                {
                    drivers->commandScheduler.addCommand(command);
                }
            }
            if (!curTrigState)
            {
                drivers->commandScheduler.removeCommand(command, false);
            }
            break;
        }
    }
    prevTrigState = curTrigState;
}

bool operator==(const TriggerBinding &binding1, const TriggerBinding &binding2)
{
    return binding1.command->getGlobalIdentifier() == binding2.command->getGlobalIdentifier() &&
           binding1.type == binding2.type;
}

bool operator!=(const TriggerBinding &binding1, const TriggerBinding &binding2)
{
    return !(binding1 == binding2);
}

